module TransformJobStatus =
  struct
    type nonrec t =
      | InProgress 
      | Completed 
      | Failed 
      | Stopping 
      | Stopped 
      | Non_static_id of string 
    let make i = i
    let to_string =
      function
      | InProgress -> "InProgress"
      | Completed -> "Completed"
      | Failed -> "Failed"
      | Stopping -> "Stopping"
      | Stopped -> "Stopped"
      | Non_static_id s -> s
    let of_string =
      function
      | "InProgress" -> InProgress
      | "Completed" -> Completed
      | "Failed" -> Failed
      | "Stopping" -> Stopping
      | "Stopped" -> Stopped
      | x -> Non_static_id x
    let to_value x = `Enum (to_string x)
    let to_query v = to_query to_value v
    let to_header x = to_string x
    let of_xml xml_arg0 =
      of_string
        (string_of_xml ~kind:"enumeration TransformJobStatus" xml_arg0)
    let of_json j = of_string (string_of_json ~kind:"TransformJobStatus" j)
    let to_json = simple_to_json to_value
  end
